// ── Types ────────────────────────────────────────────────────────────

type Lang = "en" | "bn";
type VerbType = "perfect" | "imperfect" | "imperative" | "jussive" | "subjunctive" | "passive";

interface VerbForm {
  ar: string;
  tr: string;
  ty: VerbType;
  n: number;
  mn: Record<Lang, string>;
  ex: [number, number];
}

interface Verb {
  id: number;
  root: string;
  verb: string;
  tr: string;
  form: string;
  freq: number;
  color: string;
  mn: Record<Lang, string>;
  forms: VerbForm[];
}

interface QuizQuestion {
  form: VerbForm;
  correct: string;
  options: string[];
}

