// ── Derived constants ────────────────────────────────────────────────

const TOTAL_FORMS = VERBS.reduce((sum, v) => sum + v.forms.length, 0);
const TOTAL_OCCURRENCES = VERBS.reduce((sum, v) => sum + v.freq, 0);

// ── Utilities ────────────────────────────────────────────────────────

const LOCALE: Record<Lang, string> = { en: "en-US", bn: "bn-BD" };

function fmtNum(n: number, lang: Lang): string {
  return n.toLocaleString(LOCALE[lang]);
}

function fmtPct(s: string, lang: Lang): string {
  return lang === "bn" ? s.replace(/[0-9]/g, d => String.fromCharCode(0x09E6 + +d)) : s;
}

function shuffle<T>(array: T[]): T[] {
  const result = [...array];
  for (let i = result.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [result[i], result[j]] = [result[j], result[i]];
  }
  return result;
}

function buildQuizQuestions(verb: Verb, lang: Lang, typeFilter?: VerbType): QuizQuestion[] {
  const pool = typeFilter ? verb.forms.filter(f => f.ty === typeFilter) : verb.forms;
  if (pool.length < 2) return [];
  return shuffle(pool).map(form => {
    const correct = form.mn[lang];
    let candidates = pool.filter(f => f !== form);
    if (candidates.length < 3) {
      candidates = candidates.concat(verb.forms.filter(f => f !== form && !candidates.includes(f)));
    }
    const distractors = shuffle(candidates).slice(0, 3).map(f => f.mn[lang]);
    return { form, correct, options: shuffle([correct, ...distractors]) };
  });
}

function bodyFont(lang: Lang): string {
  return lang === "bn" ? "'Noto Sans Bengali', sans-serif" : "'Source Serif 4', Georgia, serif";
}

// ── Context ──────────────────────────────────────────────────────────

interface LangContextValue {
  lang: Lang;
  t: typeof translations["en"];
}

