function highlightWord(text: string, word: string): (string | React.ReactElement)[] {
  if (!word) return [text];
  const strip = (s: string) => s.replace(/[\u064B-\u065F\u0670]/g, "");
  const plainText = strip(text);
  const plainWord = strip(word);
  const parts: (string | React.ReactElement)[] = [];
  let lastIdx = 0;
  let searchFrom = 0;
  while (searchFrom < plainText.length) {
    const idx = plainText.indexOf(plainWord, searchFrom);
    if (idx === -1) break;
    let origStart = 0, plainCount = 0;
    for (let i = 0; i < text.length && plainCount < idx; i++) {
      if (!/[\u064B-\u065F\u0670]/.test(text[i])) plainCount++;
      origStart = i + 1;
    }
    let origEnd = origStart, pCount = 0;
    for (let i = origStart; i < text.length && pCount < plainWord.length; i++) {
      if (!/[\u064B-\u065F\u0670]/.test(text[i])) pCount++;
      origEnd = i + 1;
    }
    if (origStart > lastIdx) parts.push(text.slice(lastIdx, origStart));
    parts.push(<span key={idx} style={{ color: "#a67c52", fontWeight: 700, background: "rgba(166,124,82,0.12)", borderRadius: 4, padding: "0 2px" }}>{text.slice(origStart, origEnd)}</span>);
    lastIdx = origEnd;
    searchFrom = idx + plainWord.length;
  }
  if (lastIdx < text.length) parts.push(text.slice(lastIdx));
  return parts;
}


const AyahModal = ({ form, onClose }: { form: VerbForm; onClose: () => void }) => {
  const { lang } = useLang();
  const [s, a] = form.ex;
  const ayah = AYAHS[`${s}:${a}`];
  const surah = SURAH_NAMES[s];
  if (!ayah || !surah) return null;

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === "Escape") onClose(); };
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [onClose]);

  return createPortal(
    <div data-qv="" style={{ position: "fixed", inset: 0, background: "rgba(44,24,16,0.5)", backdropFilter: "blur(6px)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1200, animation: "fi 0.2s ease", fontFamily: "'Source Serif 4',Georgia,serif" }} onClick={onClose}>
      <div role="dialog" aria-modal="true" onClick={e => e.stopPropagation()} style={{ background: "#fdfbf7", borderRadius: 18, maxWidth: 500, width: "90%", maxHeight: "85vh", overflowY: "auto", boxShadow: "0 24px 80px rgba(44,24,16,0.25)", position: "relative", animation: "fs 0.25s ease" }}>
        <div style={{ background: "linear-gradient(135deg,#a67c52,#8b6914)", padding: "16px 20px", borderRadius: "18px 18px 0 0", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ fontSize: 13, color: "rgba(255,255,255,0.8)", fontWeight: 600, fontFamily: bodyFont(lang) }}>{surah.en} ({fmtNum(s, lang)}:{fmtNum(a, lang)})</div>
            <div style={{ fontFamily: "'Amiri',serif", fontSize: 17, color: "#fff", marginTop: 2 }}>سورة {surah.ar}</div>
          </div>
          <button onClick={onClose} aria-label="Close" style={{ background: "rgba(255,255,255,0.15)", border: "none", fontSize: 18, color: "#fff", cursor: "pointer", width: 32, height: 32, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>×</button>
        </div>
        <div style={{ direction: "rtl", fontFamily: "'Amiri',serif", fontSize: 26, lineHeight: 2, color: "#2c1810", textAlign: "center", padding: "24px 22px" }}>{highlightWord(ayah.ar, form.ar)}</div>
        <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "0 22px" }}>
          <div style={{ flex: 1, height: 1, background: "#e8e0d4" }} />
          <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 14px", background: "#f5f0e8", borderRadius: 99 }}>
            <span style={{ fontFamily: "'Amiri',serif", fontSize: 20, color: "#a67c52", fontWeight: 700 }}>{form.ar}</span>
            <span style={{ fontSize: 13, color: "#8b7355", fontFamily: bodyFont(lang) }}>{form.mn[lang]}</span>
          </div>
          <div style={{ flex: 1, height: 1, background: "#e8e0d4" }} />
        </div>
        <div style={{ fontSize: 15, lineHeight: 1.7, color: "#4a3728", fontFamily: bodyFont(lang), padding: "18px 22px 22px" }}>{ayah[lang === "bn" ? "bn" : "en"]}</div>
      </div>
    </div>,
    document.body,
  );
};

const AyahRef = ({ form }: { form: VerbForm }) => {
  const [open, setOpen] = useState(false);
  const [s, a] = form.ex;
  if (!s) return null;
  return (
    <>
      <span onClick={e => { e.stopPropagation(); setOpen(true); }} style={{ fontSize: 10, color: "#c4b8a8", fontFamily: "'Source Serif 4',Georgia,serif", marginLeft: 5, cursor: "pointer", borderBottom: "1px dotted #d4c8b8" }}>({s}:{a})</span>
      {open && <AyahModal form={form} onClose={() => setOpen(false)} />}
    </>
  );
};

